mapper.select:
SELECT FROM tower t INNER JOIN property p ON p.id = t.property_id WHERE t.is_deleted = FALSE
AND (LOWER(t.tower_code) LIKE CONCAT('%', LOWER(#{search}), '%') OR LOWER(t.tower_name) LIKE CONCAT('%', LOWER(#{search}), '%') OR LOWER(p.property_code) LIKE CONCAT('%', LOWER(#{search}), '%'))
ORDER BY t.id DESC LIMIT #{limit} OFFSET #{offset}
